import{c as n,Q as s,j as e,m as p}from"./chunks/framework.iD28w_5a.js";const u=JSON.parse('{"title":"000-env-toolchain-2 · 环境搭建","description":"","frontmatter":{"title":"000-env-toolchain-2 · 环境搭建"},"headers":[],"relativePath":"hands-on/000-env-toolchain-2.md","filePath":"hands-on/000-env-toolchain-2.md","lastUpdated":1779686691000}'),o={name:"hands-on/000-env-toolchain-2.md"};function c(d,a,l,r,t,i){return s(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="_000-2-·-mbr-存根-从汇编到-qemu-启动" tabindex="-1">000-2 · MBR 存根：从汇编到 QEMU 启动 <a class="header-anchor" href="#_000-2-·-mbr-存根-从汇编到-qemu-启动" aria-label="Permalink to &quot;000-2 · MBR 存根：从汇编到 QEMU 启动&quot;">​</a></h1><blockquote><p><strong>本篇目标</strong>：编写一个最小的 MBR 汇编文件， 配置 boot 子目录的 CMakeLists.txt， 构建磁盘镜像并在 QEMU 中启动验证。</p><p><strong>完成后的效果</strong>：<code>make run</code> 启动 QEMU， 屏幕左上角出现蓝底白字的 &quot;C&quot;，CPU 停机。</p><p><strong>前置</strong>：完成 000-1（工具链安装 + CMake 配置）。</p></blockquote><hr><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="mbr-是什么-为什么它是-os-的起点" tabindex="-1">MBR 是什么，为什么它是 OS 的起点 <a class="header-anchor" href="#mbr-是什么-为什么它是-os-的起点" aria-label="Permalink to &quot;MBR 是什么，为什么它是 OS 的起点&quot;">​</a></h3><p>当你按下电脑电源键的那一刻， CPU 从一个固定的物理地址开始执行固件代码（BIOS 或 UEFI）， 这段代码做完硬件自检（POST）之后， 会从启动盘的第一个扇区读取 512 字节数据， 加载到物理内存地址 <code>0x7C00</code>，然后把控制权交给它。 这个 512 字节就是 <strong>MBR（Master Boot Record）</strong>， 它是整个操作系统启动链条的第一环。</p><p>为什么是 512 字节？因为硬盘的一个扇区就是 512 字节， 这是 IBM PC 时代留下来的约定。 为什么是 <code>0x7C00</code>？ 这同样是 BIOS 规范定义的固定地址， 所有的 x86 BIOS 都会在这个地址加载 MBR，不会有例外。</p><p>MBR 的最后两个字节必须是 <code>0x55</code> 和 <code>0xAA</code> （合在一起看是 <code>0xAA55</code>）， BIOS 会检查这个&quot;魔数&quot;， 如果不对就认为这不是一个有效的启动扇区，直接报错。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BIOS -&gt; MBR 启动流程：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Power On</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>  POST (加电自检)</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>  BIOS 读磁盘扇区 0 -&gt; 加载到 0x7C00</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>  检查偏移 510-511 是否为 0x55 0xAA</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>  跳转到 CS:IP 执行</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>  [你的 MBR 代码] &lt;- 接力棒在这里交接</span></span>
<span class="line"><span></span></span>
<span class="line"><span>MBR 512B 布局（tag 000 版本，无分区表）：</span></span>
<span class="line"><span>  +----------------------------+ 0x000</span></span>
<span class="line"><span>  | 引导代码 (&lt;= 510 bytes)    |</span></span>
<span class="line"><span>  +----------------------------+ 0x1FE</span></span>
<span class="line"><span>  | 签名 0x55 0xAA             |</span></span>
<span class="line"><span>  +----------------------------+ 0x200</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><p>MBR 虽然只有 512 字节（而且扣掉分区表和签名之后 实际可用的只有 446 字节左右）， 但它可以做很多事情 ——加载更多的扇区到内存、初始化显示模式、 进入保护模式甚至长模式， 然后把内核加载进来并跳转过去。 当然，这是后面章节的事情。 在 tag 000 里，我们的 MBR 只是一个&quot;存根&quot;： 清屏、打印一个字母、停机。 它的唯一目的是验证整个构建链条是通的 ——从汇编源码到目标文件、 从链接到 objcopy 生成裸二进制、 从 dd 写入磁盘镜像到 QEMU 启动。</p><h3 id="vga-文本模式-最简单的屏幕输出方式" tabindex="-1">VGA 文本模式：最简单的屏幕输出方式 <a class="header-anchor" href="#vga-文本模式-最简单的屏幕输出方式" aria-label="Permalink to &quot;VGA 文本模式：最简单的屏幕输出方式&quot;">​</a></h3><p>在还没有显卡驱动、没有字体渲染器的时候， 怎么在屏幕上显示字符？ 答案是 VGA 文本模式 ——这是一种硬件级的文本显示机制， 由 VGA 兼容显卡直接支持，不需要安装任何驱动。</p><p>文本模式的显存被映射到物理地址 <code>0xB8000</code>， 它不是一块普通的内存，而是显卡直接监控的区域 ——你往这里写数据，屏幕上立刻就能看到对应的变化。 屏幕被分成 80 列 x 25 行共 2000 个字符单元， 每个单元占 2 字节： 第一个字节是字符的 ASCII 码， 第二个字节是显示属性。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VGA 文本模式显存布局：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  物理地址 0xB8000</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>  +---+---+---+---+---+---+     ---+</span></span>
<span class="line"><span>  | C |1F |   |07 |   |07 | ...   |  80 columns x 25 rows</span></span>
<span class="line"><span>  +---+---+---+---+---+---+     ---+</span></span>
<span class="line"><span>  |char|attr|char|attr| ...       每个字符单元 2 字节</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  属性字节位域：</span></span>
<span class="line"><span>    bit 7    : 闪烁 (BL)</span></span>
<span class="line"><span>    bit 6-4  : 背景色 (3 bits, 8 种颜色)</span></span>
<span class="line"><span>    bit 3    : 亮度 (I)</span></span>
<span class="line"><span>    bit 2-0  : 前景色 (3 bits, 8 种颜色)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  常用属性值：</span></span>
<span class="line"><span>    0x07 = 灰底黑字（默认）</span></span>
<span class="line"><span>    0x1F = 蓝底白字</span></span>
<span class="line"><span>    0x4E = 红底黄字</span></span>
<span class="line"><span>    0x2A = 绿底亮绿字</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><p>属性字节的低 4 位控制前景色， 中间 3 位控制背景色， 最高位控制是否闪烁。 比如属性值 <code>0x1F</code> 就是蓝底白字 （背景色 1=蓝色，前景色 F=亮白色）。</p><p>这意味着在实模式下（BIOS 刚把 MBR 加载进来的时候）， 我们只需要把段寄存器 ES 指向 <code>0xB800</code> 段 （实模式下段基址需要左移 4 位，<code>0xB800 x 16 = 0xB8000</code>）， 然后用普通的内存写入指令往 ES:DI 写数据， 就能在屏幕上看到字符了。 不需要调任何 BIOS 中断， 不需要初始化任何硬件——直接写内存就行。</p><h3 id="at-t-汇编语法-和-intel-语法反着来" tabindex="-1">AT&amp;T 汇编语法：和 Intel 语法反着来 <a class="header-anchor" href="#at-t-汇编语法-和-intel-语法反着来" aria-label="Permalink to &quot;AT&amp;T 汇编语法：和 Intel 语法反着来&quot;">​</a></h3><p>Cinux 使用 GNU AS 汇编器，它默认采用 AT&amp;T 语法。 如果你之前看过的教程用的是 NASM（Intel 语法）， 刚接触 AT&amp;T 语法会有点别扭， 因为操作数顺序是反的： AT&amp;T 语法里是&quot;源操作数, 目标操作数&quot;， Intel 语法里是&quot;目标操作数, 源操作数&quot;。 另外 AT&amp;T 语法里寄存器前面要加 <code>%</code>， 立即数前面要加 <code>$</code>， 内存寻址用 <code>offset(base, index, scale)</code> 的格式。 习惯了就好，后面全篇都会用这个语法。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AT&amp;T vs Intel 语法对比：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  操作          AT&amp;T                    Intel</span></span>
<span class="line"><span>  ----          ----                    -----</span></span>
<span class="line"><span>  寄存器        %ax                     ax</span></span>
<span class="line"><span>  立即数        $0x7C00                 0x7C00</span></span>
<span class="line"><span>  内存写        mov %ax, %es:(0)        mov word [es:0], ax</span></span>
<span class="line"><span>  内存读        mov 0x10(%ebp), %eax    mov eax, dword [ebp+0x10]</span></span>
<span class="line"><span>  寻址          disp(base, index, s)    [base + index*s + disp]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><hr><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-3-编写-mbr-存根" tabindex="-1">Step 3: 编写 MBR 存根 <a class="header-anchor" href="#step-3-编写-mbr-存根" aria-label="Permalink to &quot;Step 3: 编写 MBR 存根&quot;">​</a></h3><p><strong>目标</strong>：编写一个最小的 MBR 汇编文件， 能在 QEMU 里清屏并显示一个蓝色背景的字母 &quot;C&quot;，然后停机。</p><p><strong>设计思路</strong>：MBR 存根是整个构建链的&quot;hello world&quot; ——它的代码逻辑极其简单（清屏、写字符、停机）， 但它验证了从汇编源码到最终 QEMU 运行的完整流水线： GNU AS 把 <code>.S</code> 文件汇编成 ELF 目标文件 -&gt; ld 链接成 ELF 可执行文件 -&gt; objcopy 把 ELF 转成裸二进制 -&gt; dd 写入磁盘镜像 -&gt; QEMU 从镜像启动并执行。</p><p>代码运行在 16 位实模式下（用 <code>.code16</code> 指令告诉汇编器）， BIOS 将 MBR 加载到 <code>0x7C00</code> 后从这里开始执行。 我们需要做的事情分三步： 先把 VGA 文本模式的显存全部清成空格（2000 个字符单元）， 属性设为 <code>0x07</code>（黑底灰字）； 然后在左上角（位置 0）写一个字符 &#39;C&#39;， 属性设为 <code>0x1F</code>（蓝底白字）； 最后关中断（<code>cli</code>）并停机（<code>hlt</code>）， 进入死循环防止 CPU 继续往下执行未初始化的内存。</p><p>文件末尾需要用 <code>.org 510</code> 指令跳转到偏移 510， 然后用 <code>.word 0xAA55</code> 写入签名 ——注意这里是小端序， 在文件里实际存储的是字节 <code>0x55 0xAA</code>， 但 BIOS 读取时当作 <code>0xAA55</code> 来验证。</p><p><strong>实现约束</strong>：</p><p>文件路径是 <code>boot/mbr.S</code>， 需要声明 <code>.section .text</code>、<code>.code16</code> 和 <code>.global _start</code>。 入口标签是 <code>_start</code>。 清屏操作使用 <code>rep stosw</code> 指令 （重复存储 AX 到 ES:DI 指向的内存，每次 DI 自增 2）， 需要在执行前设置 ES 段寄存器为 <code>0xB800</code>、 DI 为 0、AX 为 <code>0x0720</code>（空格字符 + 灰色属性）、 CX 为 2000。 方向标志用 <code>cld</code> 清零确保 DI 递增。 打印字符操作直接把 AX （属性字节在 AH，字符在 AL）写入 ES:0 即可。 最后需要 <code>.org 510</code> 和 <code>.word 0xAA55</code> 确保文件恰好 512 字节。</p><p>同时需要编写 <code>boot/CMakeLists.txt</code> 来编译这个文件： 定义一个可执行目标（名字叫 <code>mbr</code>）， 源文件是 <code>mbr.S</code>， 编译选项用 <code>-Wa,--32</code> （生成 32 位目标文件以兼容 16 位代码）， 链接选项指定 <code>-Wl,-m,elf_i386</code>（32 位 ELF 格式）、 链接脚本和 <code>-nostdlib -no-pie</code>。 链接脚本在 CMake configure 时生成（用 <code>file(WRITE ...)</code>）， 设置 <code>OUTPUT_FORMAT(&quot;elf32-i386&quot;)</code>、入口地址为 <code>0x7C00</code>。 <code>.text</code> 段里同时包含 <code>.rodata</code> （这样 MBR 里嵌入的字符串常量会和代码放在一起）。 最后用 <code>add_custom_command</code> 在链接后自动执行 <code>objcopy -O binary</code> 把 ELF 转成裸二进制（<code>mbr.bin</code>）。</p><p><strong>踩坑预警</strong>：<code>.org 510</code> 确保签名在正确位置。 如果代码部分超过 510 字节， 汇编器会报错。 MBR 的代码空间非常紧张（最多 510 字节减去代码长度）， 但 tag 000 的存根代码很短，不会有这个问题。 后续章节扩展 MBR 功能时需要特别注意。</p><p>另外，AT&amp;T 语法里往绝对内存地址写数据的方式是 <code>mov %ax, %es:(0)</code> 或者 <code>movw %ax, %es:0</code> ——注意冒号前面是段寄存器，后面是偏移量。 如果你习惯 Intel 语法的 <code>mov word [es:0], ax</code>， 转换过来可能会搞混操作数顺序。</p><p><strong>验证</strong>：编译 MBR 目标后， 确认 <code>build/boot/mbr.bin</code> 文件存在且大小恰好为 512 字节 （用 <code>ls -la</code> 或 <code>stat</code> 命令查看）。 用 <code>xxd</code> 查看文件的最后两个字节，应该看到 <code>55aa</code>。 用 <code>xxd</code> 查看文件开头几个字节， 应该能看到对应的机器码。</p><hr><h3 id="step-4-构建磁盘镜像并在-qemu-中运行" tabindex="-1">Step 4: 构建磁盘镜像并在 QEMU 中运行 <a class="header-anchor" href="#step-4-构建磁盘镜像并在-qemu-中运行" aria-label="Permalink to &quot;Step 4: 构建磁盘镜像并在 QEMU 中运行&quot;">​</a></h3><p><strong>目标</strong>：编写镜像构建脚本， 把 MBR 裸二进制写入磁盘镜像的第一个扇区， 然后用 QEMU 启动验证。</p><p><strong>设计思路</strong>：QEMU 需要一个磁盘镜像文件来模拟硬盘启动。 磁盘镜像本质上就是一个 raw 格式的二进制文件， 字节内容和真实硬盘上的数据完全一致。 MBR 必须出现在第 0 个扇区 （文件偏移 0-511 字节）， 后续的 stage2 和内核会从第 1 个扇区开始存放。 我们用 Linux 的 <code>dd</code> 命令来完成这个操作 ——它可以把一个文件的内容精确地写入另一个文件的指定偏移位置。</p><p><strong>实现约束</strong>：</p><p>构建脚本 <code>scripts/build_image.sh</code> 使用 <code>set -e</code> （任何命令失败立即退出）， 接收参数包括 MBR 路径、stage2 路径、内核路径和输出镜像路径 （都可以有默认值）。 脚本依赖日志模块来打印带颜色的状态信息。 核心流程是： 先用 <code>dd if=/dev/zero</code> 创建一个全零的空白镜像文件（1MB 足够）， 然后 <code>dd if=mbr.bin of=image.img bs=512 count=1 conv=notrunc</code> 把 MBR 裸二进制写入第 0 扇区。 签名验证部分使用 <code>dd bs=1 skip=510 count=2</code> 提取最后两个字节， 管道到 <code>xxd -p</code> 转成十六进制字符串， 然后和 <code>55aa</code> 比较。</p><p>在 CMake 层面， <code>cmake/qemu.cmake</code> 注册了 <code>make run</code> target， 它会先依赖镜像构建（<code>DEPENDS image</code>）， 然后启动 QEMU 并传入磁盘镜像路径。</p><p><strong>踩坑预警</strong>：<code>dd</code> 命令的 <code>conv=notrunc</code> 参数非常关键 ——没有它的话，<code>dd</code> 会在写入完成后把输出文件截断到写入的长度， 导致后续写入 stage2 和内核时文件被截断。 这会在后续章节引入 stage2 后造成非常诡异的 bug （stage2 被写入但文件长度被截回 512 字节， QEMU 读到一堆零直接崩溃）。</p><p>另一个常见的坑是 QEMU 启动后屏幕一片漆黑但没有任何报错 ——这种情况多半是 MBR 签名写错了或者文件大小不对。 用 <code>xxd</code> 检查镜像第 510-511 字节，确认是 <code>55aa</code>。</p><p><strong>验证</strong>：运行 <code>make run</code> （或者直接用 QEMU 命令行指定磁盘镜像）， QEMU 窗口应该弹出一个黑底屏幕， 左上角显示蓝底白字的字母 &quot;C&quot;， 然后 CPU 停机（不再有任何活动）。 关闭 QEMU 窗口回到终端，没有报错。</p><hr><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><h3 id="问题-qemu-启动后黑屏-没有任何输出" tabindex="-1">问题：QEMU 启动后黑屏，没有任何输出 <a class="header-anchor" href="#问题-qemu-启动后黑屏-没有任何输出" aria-label="Permalink to &quot;问题：QEMU 启动后黑屏，没有任何输出&quot;">​</a></h3><p>排查步骤： 先用 <code>xxd build/boot/mbr.bin | tail -1</code> 检查 MBR 文件最后两个字节是不是 <code>55aa</code>。 如果不是，说明签名写错了或者文件大小不对（不是 512 字节）。 如果签名正确但仍然黑屏， 用 <code>xxd build/cinux.img | head -20</code> 检查镜像的前几十个字节， 确认 MBR 内容确实被写入了第 0 扇区。 如果镜像全是零，说明 <code>build_image.sh</code> 的路径参数不对。</p><h3 id="问题-编译成功但-mbr-bin-不是-512-字节" tabindex="-1">问题：编译成功但 mbr.bin 不是 512 字节 <a class="header-anchor" href="#问题-编译成功但-mbr-bin-不是-512-字节" aria-label="Permalink to &quot;问题：编译成功但 mbr.bin 不是 512 字节&quot;">​</a></h3><p>检查链接脚本中的 <code>.org 510</code> 是否正确。 如果用了 <code>.fill</code> 语法， 确认计算方式 <code>510 - (. - _start)</code> 没有溢出。 如果代码本身超过 510 字节，汇编器会报错 ——但这种情况下需要精简代码。</p><h3 id="问题-想看-mbr-的实际机器码" tabindex="-1">问题：想看 MBR 的实际机器码 <a class="header-anchor" href="#问题-想看-mbr-的实际机器码" aria-label="Permalink to &quot;问题：想看 MBR 的实际机器码&quot;">​</a></h3><p>用 <code>objdump -D -b binary -m i8086 build/boot/mbr.bin</code> 可以反汇编裸二进制文件， 以 16 位模式查看实际生成的指令。 对比源码确认每条指令都被正确编码。</p><hr><h2 id="本篇小结" tabindex="-1">本篇小结 <a class="header-anchor" href="#本篇小结" aria-label="Permalink to &quot;本篇小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>MBR</td><td>BIOS 加载第一扇区到 <code>0x7C00</code>，512 字节，必须以 <code>0xAA55</code> 结尾</td></tr><tr><td>VGA 文本模式</td><td>显存映射在 <code>0xB8000</code>，80x25，每字符 2 字节（字符+属性）</td></tr><tr><td>AT&amp;T 汇编语法</td><td><code>src, dst</code> 顺序，寄存器 <code>%</code> 前缀，立即数 <code>$</code> 前缀</td></tr><tr><td><code>.code16</code></td><td>告诉汇编器生成 16 位实模式指令</td></tr><tr><td><code>rep stosw</code></td><td>重复存储 AX 到 ES:DI，用于快速清屏</td></tr><tr><td>objcopy</td><td>ELF -&gt; 裸二进制转换，<code>-O binary</code> 参数</td></tr><tr><td><code>conv=notrunc</code></td><td>dd 必须加此参数，否则镜像被截断</td></tr></tbody></table><p>到这里我们已经把从汇编源码到 QEMU 启动的完整构建链条跑通了： MBR 存根编译、链接、转换为裸二进制、写入磁盘镜像、QEMU 启动验证。 下一篇我们将搭建测试框架， 为后续的内核开发提供持续验证的能力。</p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>OSDev Wiki — <a href="https://wiki.osdev.org/MBR_(x86)" target="_blank" rel="noreferrer">MBR (x86)</a>: MBR 格式规范和 BIOS 加载行为</li><li>OSDev Wiki — <a href="https://wiki.osdev.org/Real_Mode" target="_blank" rel="noreferrer">Real Mode</a>: 实模式寻址机制和段寄存器</li><li>Wikipedia — <a href="https://en.wikipedia.org/wiki/VGA-compatible_text_mode" target="_blank" rel="noreferrer">VGA-compatible text mode</a>: VGA 文本缓冲区地址和属性字节格式</li><li>OSDev Wiki — <a href="https://wiki.osdev.org/Bare_Bones" target="_blank" rel="noreferrer">Bare Bones</a>: freestanding 环境和编译 flag 参考</li></ul>`,57)])])}const m=n(o,[["render",c]]);export{u as __pageData,m as default};
